// ═══════════════════════════════════════════════════════
// NODO: Generate Embedding - OPTIMIZADO PARA BÚSQUEDA SEMÁNTICA
// ═══════════════════════════════════════════════════════

const property = $input.item.json;

console.log('═══════════════════════════════════════');
console.log('📝 Procesando propiedad:', property.tokkoId || property.id);

// Extraer datos
const tokkoId = property.tokkoId || property.id || '';
const titulo = property.titulo || property.publication_title || '';
const tipoOperacion = property.operacion || property.tipo_operacion || '';
const precio = property.precio || null;
const moneda = property.moneda || 'USD';
const distrito = property.distrito || '';
const direccion = property.direccion || '';
const habitaciones = property.habitaciones || 0;
const banos = property.banos || 0;
const cocheras = property.cocheras || 0;
const superficie = property.areaConstruida || property.area_construida || 0;
const tipoInmueble = property.tipoInmueble || property.tipo_inmueble || '';
const asesor = property.asesor || '';
const imagen = property.imagen || '';
const linkWeb = property.linkWeb || property.link_web || '';
const descripcion = property.descripcion || property.description || '';

// ═══════════════════════════════════════════════════════
// EXTRAER CALLE Y ALTURA DE LA DIRECCIÓN
// ═══════════════════════════════════════════════════════
let calle = '';
let altura = '';

if (direccion) {
  // Intentar separar calle y número
  // Ej: "Cabezas 2500" → calle="Cabezas", altura="2500"
  const dirMatch = direccion.match(/^(.+?)\s+(\d+)$/);
  if (dirMatch) {
    calle = dirMatch[1].trim();
    altura = dirMatch[2];
  } else {
    calle = direccion.trim();
  }
}

console.log('✅ Datos extraídos:', {
  tokkoId,
  titulo: titulo.substring(0, 30),
  direccion,
  calle,
  altura,
  distrito
});

// ═══════════════════════════════════════════════════════
// METADATA ESTRUCTURADA (para filtros)
// ═══════════════════════════════════════════════════════
const metadata = {
  tokko_id: tokkoId.toString(),
  codigo: property.codigo || '',
  titulo: titulo,
  direccion: direccion,
  calle: calle,  // 🆕 Campo nuevo
  altura: altura, // 🆕 Campo nuevo
  distrito: distrito,
  zona: distrito, // Alias para búsquedas
  barrio: distrito, // Alias para búsquedas
  precio: precio,
  moneda: moneda,
  ambientes: habitaciones, // En Argentina: ambientes
  dormitorios: habitaciones > 0 ? habitaciones - 1 : 0, // dormitorios = ambientes - 1
  habitaciones: habitaciones,
  banos: banos,
  cocheras: cocheras,
  area_construida: superficie,
  tipo_inmueble: tipoInmueble,
  tipo_propiedad: tipoInmueble, // Alias
  tipo_operacion: tipoOperacion,
  operacion: tipoOperacion.toLowerCase(), // "venta" o "alquiler"
  asesor: asesor,
  imagen: imagen,
  link_web: linkWeb,
  geo_lat: property.geoLat?.toString() || '',
  geo_long: property.geoLong?.toString() || ''
};

// ═══════════════════════════════════════════════════════
// TEXTO PARA EMBEDDING (lenguaje natural)
// ═══════════════════════════════════════════════════════

// Construir descripción de precio
let textoPrecio = '';
if (precio) {
  const precioFormateado = precio.toLocaleString('es-AR');
  textoPrecio = `${moneda} ${precioFormateado}`;
} else {
  textoPrecio = 'Precio a consultar';
}

// Construir descripción de ambientes/dormitorios
let textoAmbientes = '';
if (habitaciones > 0) {
  const dormitorios = habitaciones - 1;
  if (habitaciones === 1) {
    textoAmbientes = 'monoambiente';
  } else if (dormitorios === 1) {
    textoAmbientes = `${habitaciones} ambientes (${dormitorios} dormitorio)`;
  } else {
    textoAmbientes = `${habitaciones} ambientes (${dormitorios} dormitorios)`;
  }
}

// Construir descripción de ubicación
let textoUbicacion = '';
if (direccion && distrito) {
  textoUbicacion = `en ${direccion}, ${distrito}`;
} else if (direccion) {
  textoUbicacion = `en ${direccion}`;
} else if (distrito) {
  textoUbicacion = `en ${distrito}`;
}

// Construir características adicionales
const caracteristicas = [];
if (banos > 0) caracteristicas.push(`${banos} baño${banos > 1 ? 's' : ''}`);
if (cocheras > 0) caracteristicas.push(`${cocheras} cochera${cocheras > 1 ? 's' : ''}`);
if (superficie > 0) caracteristicas.push(`${superficie}m²`);

const textoCaracteristicas = caracteristicas.length > 0 
  ? caracteristicas.join(', ') + '.'
  : '';

// Limpiar descripción (primeros 300 caracteres)
const textoDescripcion = descripcion 
  ? descripcion.substring(0, 300).trim() + '...'
  : '';

// ═══════════════════════════════════════════════════════
// TEXTO COMPLETO EN LENGUAJE NATURAL
// ═══════════════════════════════════════════════════════
const textoCompleto = `
${tipoInmueble} ${textoAmbientes} ${textoUbicacion}.
${tipoOperacion} ${textoPrecio}.
${textoCaracteristicas}
${titulo}
${textoDescripcion}
`.trim().replace(/\s+/g, ' ');

console.log('📦 Texto generado:', textoCompleto.substring(0, 150) + '...');
console.log('═══════════════════════════════════════');

// Retornar
return {
  json: {
    text: textoCompleto,
    metadata: metadata
  }
};

// Extraer y preparar cada propiedad individualmente
const data = $input.first().json;
const properties = data.objects || [];

console.log(`=== TOKKO PROPERTIES PROCESSING ===`);
console.log(`Total properties found: ${properties.length}`);

// Crear un item por cada propiedad
const items = [];

properties.forEach((property, index) => {
  // Función helper para obtener precio por tipo de operación
  const getPriceByOperation = (operations, operationType, currency) => {
    const operation = operations?.find(op => op.operation_type === operationType);
    const price = operation?.prices?.find(p => p.currency === currency);
    return price?.price || null;
  };

  // Función helper para obtener moneda por tipo de operación
  const getCurrencyByOperation = (operations, operationType) => {
    const operation = operations?.find(op => op.operation_type === operationType);
    return operation?.prices?.[0]?.currency || 'USD';
  };

  // Función helper para obtener operaciones
  const getOperations = (operations) => {
    return operations?.map(op => op.operation_type).join(', ') || '';
  };

  // ═══════════════════════════════════════════════════════
  // FUNCIÓN PARA EXTRAER PRIMERA IMAGEN
  // ═══════════════════════════════════════════════════════
  const getPrimeraImagen = (photos) => {
    if (!photos || photos.length === 0) {
      return '';  // Retorna string vacío si no hay fotos
    }

    // Ordenar fotos por el campo 'order'
    const sortedPhotos = [...photos].sort((a, b) => (a.order || 0) - (b.order || 0));

    // Buscar imagen de portada (is_front_cover: true)
    const coverPhoto = sortedPhotos.find(p => p.is_front_cover === true);

    // Primera imagen (por orden o la de portada)
    const firstPhoto = coverPhoto || sortedPhotos[0];

    // Retornar la URL de la imagen
    return firstPhoto?.image || '';
  };

  const transformedProperty = {
    // Datos originales de Tokko
    tokkoId: property.id?.toString() || '',
    codigo: property.reference_code || '',
    tipoInmueble: property.type?.name || '',
    operacion: getOperations(property.operations),
    titulo: property.publication_title || '',
    direccion: property.real_address || '',
    linkWeb: property.public_url || '',
    descripcion: property.description || '',
    distrito: property.location?.name || '',
    propietarioNombre: property.internal_data?.property_owners?.[0]?.name || '',
    propietarioCelular: property.internal_data?.property_owners?.[0]?.phone || '',
    moneda: property.operations?.[0]?.operation_type === "Alquiler" ? 
      getCurrencyByOperation(property.operations, "Alquiler") : 
      getCurrencyByOperation(property.operations, "Venta"),
    precio: property.operations?.[0]?.operation_type === "Alquiler" ? 
      getPriceByOperation(property.operations, "Alquiler", "ARS") : 
      getPriceByOperation(property.operations, "Venta", "USD"),
    asesor: property.producer?.name || '',
    areaConstruida: parseFloat(property.surface) || null,
    habitaciones: property.room_amount || (property.bedroom_amount ? property.bedroom_amount + 1 : null),
    banos: property.bathroom_amount || null,
    cocheras: property.parking_lot_amount || null,
    geoLat: parseFloat(property.geo_lat) || null,
    geoLong: parseFloat(property.geo_long) || null,

    // ═══════════════════════════════════════════════════════
    // IMAGEN PRINCIPAL (NUEVO)
    // ═══════════════════════════════════════════════════════
    imagen: getPrimeraImagen(property.photos),

    // Metadatos para tracking
    propertyIndex: index + 1,
    totalProperties: properties.length,
    processedAt: new Date().toISOString()
  };

  items.push({ json: transformedProperty });
});

console.log(`Prepared ${items.length} properties for processing`);
console.log(`Properties with images: ${items.filter(i => i.json.imagen).length}`);

return items;
